// This script finds the binary file and decodes it using the older n8n method
const binaryData = $input.item.binary;
const binaryKeys = Object.keys(binaryData);

if (binaryKeys.length === 0) {
  return { my_resume_content: "ERROR: No binary file found." };
}

// Grab the first binary key (like 'data' or 'attachment')
const key = binaryKeys[0];

// In n8n v2.x, we use this helper to turn binary into a string
const textContent = await this.helpers.getBinaryDataBuffer(0, key);

return {
  my_resume_content: textContent.toString('utf-8')
};
